I wrote a plugin which registers an `Engine` for `.jsx` and `.tsx`, using [Nano JSX](https://nanojsx.io) as a renderer. It was working as intended until I wrote `tag.tsx`. While the `Engine` had `#render()` which took only `Nano.Component | Nano.FC` (the former is a class component and the latter is a function component) as its first argument, it would not work for `GeneratorFunction` from `tag.tsx`. So I had to write a special if-clause for generator. I didn't believe this is intended, so I regarded it as a bug or something.

The basic structure of my engine is:
```ts
export class NanoJsxEngine implements Engine {
  render(content: Nano.Component | Nano.FC | AsyncGeneratorFunction, data: Data) {
    if (isGenerator(content)) {
      // deno-lint-ignore no-this-alias
      const nanoEngine = this;
      return (async function* (generator: AsyncGeneratorFunction) {
        for await (const data of generator() as AsyncGenerator<Data>) {
          const content = nanoEngine.renderSync(data.content as Nano.Component, data);
          yield {content, ...data}
        }
      })(content as AsyncGeneratorFunction);
    }
    return Promise.resolve(this.renderSync(content, data));
  }

  renderSync(content: Nano.Component | Nano.FC, data: Data): string {
    if (!data.children && typeof data.content === "string") {
      // we are rendering layout
      const doc = createDocumentFragment(data.content);

      const elements = Array.from(doc.childNodes)
        .filter((node) => node.nodeType === NodeType.ELEMENT_NODE)
        .map((node) => {
          node.toString = () => (node as Element).outerHTML;
          return node;
        }) as Element[];
      data.children = elements;
    }

    const { children, ...props } = data;
    if (Array.isArray(children)) {
      return Nano.renderSSR(() => Nano.h(content, props, ...children));
    } else {
      return Nano.renderSSR(() => Nano.h(content, props, children));
    }
  }
}
```

