      }
    }
}))
```

And this code is for development:

```js
site.use(esbuild({
    extensions: [".jsx"],
    options: {
      jsxDev: true,
    }
}))
```

So this change should fix #400.

The only problem is unpkg.com doesn't resolve the dependencies versions. For example, the code:

```
