Since `<!DOCTYPE html>` is not valid JSX, but [must be included](https://html.com/tags/doctype/) in `.html` documents for best practices, I suggest adding a feature to automatically add `<!DOCTYPE html>`, to the JSX plugins. [Some more info on stackoverflow](https://stackoverflow.com/questions/48653734/react-server-side-rendering-invariant-violation-invalid-tag-doctype-html).

This can be implemented easily with the snippet taken from the [source code](https://github.com/fabon-f/website/blob/master/_config.js) of the lume showcase website [fabon.info](https://www.fabon.info/):

```js
/** Register the plugin to support JSX and TSX files */
export default function (userOptions?: Partial<Options>) {
  const options = merge(defaults, userOptions);
  const extensions = Array.isArray(options.extensions)
    ? { pages: options.extensions, components: options.extensions }
    : options.extensions;

  return (site: Site) => {
    const engine = new PreactJsxEngine();

    site.loadPages(extensions.pages, loader, engine);
    site.loadComponents(extensions.components, loader, engine);
    site.process([".html"], addDoctype)

    function addDoctype(page: Page) {
      if (!page.content?.toString().trim().startsWith("<!DOCTYPE")) {
        page.content = `<!DOCTYPE html>${page.content}`;
      }
    }
  };
}
```

